const express = require('express');
const crypto = require('crypto');

const app = express();
app.use(express.json({ limit: '256kb' }));

// ---- In-memory storage (replace with DB in production) ----
const players = new Map(); // playerId -> { playerId, createdAt, inventory, currency, progress, claims, events }
const levelCompletions = new Map(); // completionId -> completion record

function nowIso() {
  return new Date().toISOString();
}

function uid(prefix = '') {
  return prefix + crypto.randomBytes(12).toString('hex');
}

function clampNumber(n, min, max, fallback = 0) {
  const x = Number(n);
  if (!Number.isFinite(x)) return fallback;
  return Math.min(max, Math.max(min, x));
}

function getPlayer(playerId) {
  if (!playerId || typeof playerId !== 'string') return null;
  let p = players.get(playerId);
  if (!p) {
    p = {
      playerId,
      createdAt: nowIso(),
      inventory: {},
      currency: { coins: 0, gems: 0 },
      progress: { highestLevelCompleted: 0, levels: {} }, // levelId -> { bestScore, bestTimeMs, lastCompletedAt }
      claims: { rewardClaimedCompletionIds: new Set() },
      events: []
    };
    players.set(playerId, p);
  }
  return p;
}

function addInventory(p, itemId, qty) {
  if (!itemId || qty <= 0) return;
  p.inventory[itemId] = (p.inventory[itemId] || 0) + qty;
}

function addCurrency(p, coins, gems) {
  p.currency.coins += coins;
  p.currency.gems += gems;
}

function computeRewards({ levelId, score, timeMs, attempt }) {
  // Casual puzzle game reward tuning (client-reported metrics; validate and clamp only)
  // Returns deterministic reward payload for the completion.
  const lvl = clampNumber(levelId, 1, 1000000, 1);
  const s = clampNumber(score, 0, 100000000, 0);
  const t = clampNumber(timeMs, 1, 24 * 60 * 60 * 1000, 60000);
  const a = clampNumber(attempt, 1, 1000000, 1);

  // Base coins scale with level
  let coins = 10 + Math.floor(lvl * 2);

  // Score bonus
  coins += Math.floor(Math.sqrt(s) / 2);

  // Speed bonus: faster -> more coins, capped
  // timeMs: 15s to 5m typical; compute bonus between 0..50
  const speedFactor = Math.max(0, Math.min(1, (180000 - t) / 180000)); // <= 3m
  coins += Math.floor(50 * speedFactor);

  // First-try bonus
  if (a === 1) coins += 15;

  // Small gem chance based on performance
  let gems = 0;
  const performance = (Math.min(1, s / 50000) * 0.6) + (speedFactor * 0.4);
  if (performance >= 0.95) gems = 2;
  else if (performance >= 0.85) gems = 1;

  // Item drops (simple deterministic thresholding)
  const items = [];
  if (s >= 25000) items.push({ itemId: 'booster_hint', qty: 1 });
  if (speedFactor >= 0.9) items.push({ itemId: 'booster_shuffle', qty: 1 });

  // Clamp final rewards
  coins = clampNumber(coins, 0, 1000000, 0);
  gems = clampNumber(gems, 0, 1000, 0);

  return {
    coins,
    gems,
    items
  };
}

function validateLevelCompletionPayload(body) {
  const errors = [];

  const playerId = body?.playerId;
  const levelId = body?.levelId;
  const score = body?.score;
  const timeMs = body?.timeMs ?? body?.time; // allow time alias
  const attempt = body?.attempt ?? 1;

  if (typeof playerId !== 'string' || playerId.length < 1 || playerId.length > 128) {
    errors.push('playerId is required (string, 1..128 chars)');
  }
  if (!Number.isFinite(Number(levelId)) || Number(levelId) < 1) {
    errors.push('levelId is required (number >= 1)');
  }
  if (!Number.isFinite(Number(score)) || Number(score) < 0) {
    errors.push('score is required (number >= 0)');
  }
  if (!Number.isFinite(Number(timeMs)) || Number(timeMs) <= 0) {
    errors.push('timeMs is required (number > 0)');
  }
  if (!Number.isFinite(Number(attempt)) || Number(attempt) < 1) {
    errors.push('attempt must be a number >= 1');
  }

  return {
    ok: errors.length === 0,
    errors,
    data: {
      playerId,
      levelId: Number(levelId),
      score: Number(score),
      timeMs: Number(timeMs),
      attempt: Number(attempt)
    }
  };
}

// ---- Endpoints ----

app.get('/health', (req, res) => {
  res.json({ ok: true, time: nowIso() });
});

// Submit level completion; returns completionId and computed rewards preview
app.post('/v1/levels/complete', (req, res) => {
  const v = validateLevelCompletionPayload(req.body);
  if (!v.ok) return res.status(400).json({ ok: false, errors: v.errors });

  const { playerId, levelId, score, timeMs, attempt } = v.data;
  const player = getPlayer(playerId);

  const completionId = uid('cmp_');
  const rewards = computeRewards({ levelId, score, timeMs, attempt });

  const record = {
    completionId,
    playerId,
    levelId,
    score,
    timeMs,
    attempt,
    rewards,
    createdAt: nowIso(),
    claimedAt: null,
    status: 'COMPLETED' // COMPLETED -> CLAIMED
  };

  levelCompletions.set(completionId, record);

  // Update progress stats (best score / best time)
  const levelKey = String(levelId);
  const prev = player.progress.levels[levelKey] || null;
  const bestScore = prev ? Math.max(prev.bestScore, score) : score;
  const bestTimeMs = prev ? Math.min(prev.bestTimeMs, timeMs) : timeMs;

  player.progress.levels[levelKey] = {
    bestScore,
    bestTimeMs,
    lastCompletedAt: record.createdAt
  };

  player.progress.highestLevelCompleted = Math.max(player.progress.highestLevelCompleted, levelId);

  player.events.push({
    type: 'LEVEL_COMPLETED',
    at: record.createdAt,
    completionId,
    levelId,
    score,
    timeMs,
    attempt
  });

  res.json({
    ok: true,
    completion: {
      completionId,
      levelId,
      score,
      timeMs,
      attempt,
      createdAt: record.createdAt,
      status: record.status
    },
    rewardsPreview: rewards
  });
});

// Claim rewards for a completionId; idempotent
app.post('/v1/rewards/claim', (req, res) => {
  const completionId = req.body?.completionId;
  const playerId = req.body?.playerId;

  if (typeof completionId !== 'string' || completionId.length < 1) {
    return res.status(400).json({ ok: false, error: 'completionId is required' });
  }
  if (typeof playerId !== 'string' || playerId.length < 1 || playerId.length > 128) {
    return res.status(400).json({ ok: false, error: 'playerId is required' });
  }

  const player = getPlayer(playerId);
  const record = levelCompletions.get(completionId);

  if (!record) return res.status(404).json({ ok: false, error: 'completion not found' });
  if (record.playerId !== playerId) return res.status(403).json({ ok: false, error: 'completion does not belong to player' });

  // Idempotency: if already claimed, return current balances and original rewards
  if (record.status === 'CLAIMED' || player.claims.rewardClaimedCompletionIds.has(completionId)) {
    return res.json({
      ok: true,
      claimed: false,
      completionId,
      rewards: record.rewards,
      currency: player.currency,
      inventory: player.inventory
    });
  }

  // Apply rewards
  const { coins, gems, items } = record.rewards;
  addCurrency(player, coins, gems);
  for (const it of items || []) {
    const itemId = it?.itemId;
    const qty = clampNumber(it?.qty, 1, 1000000, 1);
    if (typeof itemId === 'string' && itemId.length > 0 && itemId.length <= 64) {
      addInventory(player, itemId, qty);
    }
  }

  record.status = 'CLAIMED';
  record.claimedAt = nowIso();
  player.claims.rewardClaimedCompletionIds.add(completionId);

  player.events.push({
    type: 'REWARD_CLAIMED',
    at: record.claimedAt,
    completionId,
    levelId: record.levelId,
    rewards: record.rewards
  });

  res.json({
    ok: true,
    claimed: true,
    completionId,
    rewards: record.rewards,
    currency: player.currency,
    inventory: player.inventory
  });
});

